mapper.select:
SELECT course.id AS id, course.`course_name` AS courseName, course.`course_desc` AS courseDesc, course.`course_tag` AS courseTag, course.`course_type` AS courseType, course.`teacher_id` AS teacherId, course.`start_date` AS startDate, course.`end_date` AS endDate, course.`chapters` AS chapters, course.`works` AS works, course.`answer` AS answer,
classroom.`classroom_id` AS classroomId, classroom.`name` AS classroomName, classroom.`members` AS members, classroom.`course_id` AS courseId, classroom.`teacher_id` AS classroomTeacherId
FROM course LEFT JOIN classroom ON course.id = classroom.`course_id` WHERE course.`teacher_id`= #{id} ;

SELECT notice.`course_id` AS courseId, notice.`create_time` AS createTime, notice.`content` AS content, notice.`state` AS state, notice.`id` AS id, notice.`title` AS title, course.`course_name` AS courseName, classroom.`name` AS classroomName
FROM notice LEFT JOIN `classroom` ON classroom.`course_id`=notice.`course_id` LEFT JOIN study_record ON study_record.`classroom_id`=classroom.`classroom_id` LEFT JOIN `user` ON study_record.`user_id`=user.`id` LEFT JOIN course ON classroom.`course_id`=course.`id`
WHERE user.id=#{userId} AND notice.state=1;

SELECT notice.`course_id` AS courseId, notice.`create_time` AS createTime, notice.`content` AS content, notice.`state` AS state, notice.`id` AS id, notice.`title` AS title, course.`course_name` AS courseName
FROM notice LEFT JOIN `course` ON course.`id`=notice.`course_id` LEFT JOIN `user` ON course.`teacher_id`=user.`id`
WHERE user.id=#{userId} ;
